message:
첨삭 JSON 스키마 (웹앱 렌더러 기준, 이 모양 정확히 맞춰야 함):

{
  "answer_outline": "string (필수) — 학생 답안 전개 요약 2~3문장",
  "margin_comments": [
    {
      "id": "string (필수) — uuid",
      "page": "number (필수) — 1 또는 2 (원고지 1500자, p1=0~750자, p2=800~1500자)",
      "y_position": "number (필수) — 0.0~1.0 (페이지 내 세로 위치)",
      "text": "string (필수) — 코멘트 본문",
      "type": "string (필수) — praise|improvement|error|suggestion 4개 중 하나"
    }
  ],
  "scores": [
    {
      "question_number": "number (필수)",
      "point_scores": [
        {
          "name": "string (필수) — 채점 항목명",
          "earned": "number (필수) — 득점",
          "max": "number (필수) — 배점",
          "notes": "string (선택) — 비고"
        }
      ],
      "deductions": [
        {
          "name": "string (필수)",
          "deduction": "number (필수)",
          "reason": "string (선택)"
        }
      ],
      "subtotal": "number (필수)"
    }
  ],
  "total_score": "number (필수)",
  "grade": "string (필수)",
  "summary": "string (필수) — 종합 총평",
  "strengths": "string (필수) — 잘한 부분",
  "improvements": "string (필수) — 개선 필요 부분"
}
